// Homepage — Server Component
import { createClient } from '@/lib/supabase/server'
import Link from 'next/link'
import type { ProjectWithRelations, AssignmentWithProfile } from '@/lib/types/database'
import Greeting from '@/components/ui/Greeting'

export const metadata = { title: 'Home · Forge' }

function ActionCard({ icon, title, desc, href, accent = false }: {
  icon: string; title: string; desc: string; href: string; accent?: boolean
}) {
  return (
    <Link href={href} className="feature-card-hover" style={{
      background: accent ? 'var(--accent-light)' : 'var(--bg-surface)',
      border: `1px solid ${accent ? 'rgba(201,151,58,0.3)' : 'var(--border-subtle)'}`,
      borderRadius: 16, padding: '28px 24px',
      display: 'flex', flexDirection: 'column', gap: 14,
      textDecoration: 'none', minHeight: 160,
    }}>
      <div style={{
        width: 52, height: 52, borderRadius: 14,
        background: accent ? 'rgba(201,151,58,0.15)' : 'var(--bg-overlay)',
        display: 'flex', alignItems: 'center', justifyContent: 'center',
        fontSize: 24, border: `1px solid ${accent ? 'rgba(201,151,58,0.2)' : 'var(--border-subtle)'}`,
      }}>
        {icon}
      </div>
      <div>
        <div style={{ fontSize: 15, fontWeight: 600, marginBottom: 6, color: accent ? 'var(--accent)' : 'var(--text-primary)' }}>
          {title}
        </div>
        <div style={{ fontSize: 13, color: 'var(--text-muted)', lineHeight: 1.6 }}>{desc}</div>
      </div>
    </Link>
  )
}

export default async function HomePage() {
  const supabase = await createClient()
  const { data: { user } } = await supabase.auth.getUser()

  const [{ count: projectCount }, { count: teamCount }, { count: assignmentCount }] = await Promise.all([
    supabase.from('projects').select('*', { count: 'exact', head: true }).eq('status', 'approved'),
    supabase.from('teams').select('*', { count: 'exact', head: true }),
    supabase.from('assignments').select('*', { count: 'exact', head: true }).eq('is_public', true),
  ])

  const { data: trendingRaw } = await supabase
    .from('projects')
    .select(`*, views,
      profiles!projects_submitted_by_fkey(id,username,avatar_url,full_name),
      project_tags(tag_id,tags(id,name,color)),
      project_members(profile_id,role,profiles!project_members_profile_id_fkey(id,username,avatar_url,full_name))
    `)
    .eq('status', 'approved')
    .order('star_count', { ascending: false })
    .limit(7)
  const trending = (trendingRaw as unknown as ProjectWithRelations[]) ?? []

  const { data: recentAssignmentsRaw } = await supabase
    .from('assignments')
    .select('*, profiles(id,username,avatar_url,full_name)')
    .eq('is_public', true)
    .order('created_at', { ascending: false })
    .limit(6)
  const recentAssignments = (recentAssignmentsRaw as unknown as AssignmentWithProfile[]) ?? []

  // File type → icon + color
  const fileStyle = (url: string | null) => {
    if (!url) return { icon: '📎', color: '#a09890' }
    if (url.endsWith('.pdf'))          return { icon: '📄', color: '#e74c3c' }
    if (url.match(/\.(jpg|png|jpeg)/i)) return { icon: '🖼',  color: '#3498db' }
    if (url.endsWith('.docx'))         return { icon: '📝', color: '#2980b9' }
    if (url.endsWith('.pptx'))         return { icon: '📊', color: '#e67e22' }
    return { icon: '📎', color: '#a09890' }
  }

  const hero    = trending[0]
  const restTrending = trending.slice(1)

  return (
    <div style={{ padding: '56px 48px 80px', width: '100%' }}>
      <div style={{ maxWidth: 1200, margin: '0 auto' }}>

        {/* ─── HERO ─── */}
        <div className="animate-fade-up" style={{ marginBottom: 56 }}>
          <Greeting hasUser={!!user} />
          <h1 style={{
            fontFamily: 'var(--font-cormorant), Georgia, serif',
            fontSize: 'clamp(64px, 9vw, 108px)',
            fontWeight: 400, lineHeight: 0.95, color: 'var(--text-primary)',
          }}>
            Knowledge
          </h1>
          <h1 style={{
            fontFamily: 'var(--font-cormorant), Georgia, serif',
            fontSize: 'clamp(64px, 9vw, 108px)',
            fontWeight: 300, fontStyle: 'italic',
            lineHeight: 0.95, color: 'var(--text-secondary)', marginBottom: 36,
          }}>
            doesn&apos;t graduate.
          </h1>
          <p style={{ fontSize: 16, color: 'var(--text-secondary)', maxWidth: 540, lineHeight: 1.8, fontWeight: 300 }}>
            Forge is the project-sharing and knowledge-preservation platform for ITM University.
            Submit your work permanently so future students can discover and build on top of it.
          </p>
        </div>

        {/* ─── ACTION CARDS ─── */}
        <div className="animate-fade-up delay-1" style={{
          display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))',
          gap: 16, marginBottom: 56,
        }}>
          <ActionCard href="/projects/submit" icon="＋" title="Submit Project" desc="Share your work with the university permanently" accent />
          <ActionCard href="/projects" icon="⌕" title="Browse Projects" desc="Discover what students before you have built" />
          <ActionCard href="/teams" icon="◎" title="Join a Team" desc="Collaborate with peers on your next big idea" />
        </div>

        {/* ─── STATS ─── */}
        <div className="animate-fade-up delay-2" style={{
          display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(140px, 1fr))',
          gap: 1, marginBottom: 64,
          background: 'var(--border)', borderRadius: 16, overflow: 'hidden',
          border: '1px solid var(--border)',
        }}>
          {[
            { num: projectCount   ?? 0, label: 'Projects Archived'  },
            { num: teamCount      ?? 0, label: 'Active Teams'        },
            { num: assignmentCount ?? 0, label: 'Public Assignments' },
            { num: '∞',                  label: 'Knowledge Preserved' },
          ].map(({ num, label }) => (
            <div key={label} style={{ background: 'var(--bg-surface)', padding: '28px 20px', textAlign: 'center' }}>
              <div style={{
                fontFamily: 'var(--font-cormorant), Georgia, serif',
                fontSize: 52, fontWeight: 300, color: 'var(--text-primary)',
                lineHeight: 1, marginBottom: 8,
              }}>
                {num}
              </div>
              <div style={{ fontSize: 11, color: 'var(--text-muted)', letterSpacing: '0.1em', textTransform: 'uppercase' }}>
                {label}
              </div>
            </div>
          ))}
        </div>

        {/* ─── TRENDING PROJECTS ─── */}
        <section className="animate-fade-up delay-3" style={{ marginBottom: 64 }}>
          <div style={{ display: 'flex', alignItems: 'baseline', justifyContent: 'space-between', marginBottom: 28 }}>
            <h2 style={{ fontFamily: 'var(--font-cormorant), Georgia, serif', fontSize: 40, fontWeight: 400 }}>
              Trending Projects
            </h2>
            <Link href="/projects" style={{ fontSize: 13, color: 'var(--accent)', fontWeight: 500 }}>
              View all →
            </Link>
          </div>

          {trending.length === 0 ? (
            <div style={{
              background: 'var(--bg-surface)', border: '2px dashed var(--border)',
              borderRadius: 20, padding: '60px 40px', textAlign: 'center',
            }}>
              <div style={{ fontSize: 48, opacity: 0.25, marginBottom: 16 }}>◫</div>
              <h3 style={{ fontFamily: 'var(--font-cormorant), Georgia, serif', fontSize: 26, marginBottom: 8 }}>
                No projects yet — be the first
              </h3>
              <Link href="/projects/submit" style={{
                display: 'inline-flex', alignItems: 'center', gap: 8,
                padding: '12px 28px', borderRadius: 10,
                background: 'var(--accent)', color: '#1c1917',
                fontSize: 14, fontWeight: 600, marginTop: 8,
              }}>
                Submit First Project →
              </Link>
            </div>
          ) : (
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 20 }}>

              {/* ── HERO PROJECT — large left card ── */}
              {hero && (() => {
                const tags    = hero.project_tags?.map(pt => pt.tags).filter(Boolean) ?? []
                const author  = hero.profiles
                const members = hero.project_members ?? []
                return (
                  <Link href={`/projects/${hero.id}`} style={{
                    gridRow: restTrending.length > 0 ? 'span 2' : undefined,
                    display: 'flex', flexDirection: 'column',
                    background: 'var(--bg-surface)',
                    border: '1px solid var(--border-subtle)',
                    borderRadius: 20, overflow: 'hidden',
                    textDecoration: 'none',
                    transition: 'all 0.3s cubic-bezier(0.22,1,0.36,1)',
                  }}
                  onMouseEnter={e => {
                    const el = e.currentTarget as HTMLAnchorElement
                    el.style.borderColor = 'var(--accent)'
                    el.style.boxShadow = '0 20px 60px rgba(201,151,58,0.15)'
                    el.style.transform = 'translateY(-4px)'
                  }}
                  onMouseLeave={e => {
                    const el = e.currentTarget as HTMLAnchorElement
                    el.style.borderColor = 'var(--border-subtle)'
                    el.style.boxShadow = 'none'
                    el.style.transform = 'translateY(0)'
                  }}>
                    {/* Tall thumbnail */}
                    <div style={{
                      width: '100%', flex: '1 0 260px', maxHeight: 320,
                      background: 'linear-gradient(135deg, var(--bg-overlay), var(--bg-base))',
                      overflow: 'hidden', position: 'relative',
                      display: 'flex', alignItems: 'center', justifyContent: 'center',
                      fontSize: 72, color: 'var(--text-muted)',
                    }}>
                      {hero.thumbnail_url
                        ? <img src={hero.thumbnail_url} alt={hero.title}
                            style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                        : '◫'}
                      {/* Gradient bottom */}
                      <div style={{
                        position: 'absolute', bottom: 0, left: 0, right: 0, height: '40%',
                        background: 'linear-gradient(transparent, rgba(0,0,0,0.5))',
                      }} />
                      {/* #1 badge */}
                      <div style={{
                        position: 'absolute', top: 16, left: 16,
                        fontSize: 11, padding: '5px 14px', borderRadius: 99,
                        background: 'rgba(201,151,58,0.92)', color: '#1c1917',
                        fontWeight: 700, letterSpacing: '0.08em',
                        backdropFilter: 'blur(8px)',
                      }}>
                        ★ Top Trending
                      </div>
                      {/* Star + views overlay */}
                      <div style={{
                        position: 'absolute', bottom: 14, right: 14,
                        display: 'flex', gap: 8,
                      }}>
                        <span style={{
                          fontSize: 12, padding: '4px 10px', borderRadius: 99,
                          background: 'rgba(0,0,0,0.6)', color: 'white',
                          backdropFilter: 'blur(8px)',
                        }}>
                          ★ {hero.star_count}
                        </span>
                        <span style={{
                          fontSize: 12, padding: '4px 10px', borderRadius: 99,
                          background: 'rgba(0,0,0,0.6)', color: 'white',
                          backdropFilter: 'blur(8px)',
                        }}>
                          ◎ {(hero as any).views ?? 0}
                        </span>
                      </div>
                    </div>

                    <div style={{ padding: '24px' }}>
                      <div style={{ display: 'flex', gap: 6, flexWrap: 'wrap', marginBottom: 10 }}>
                        {tags.slice(0, 4).map(t => <span key={t!.id} className="tag-pill">{t!.name}</span>)}
                      </div>
                      <h3 style={{
                        fontFamily: 'var(--font-cormorant), Georgia, serif',
                        fontSize: 28, fontWeight: 400, lineHeight: 1.1, marginBottom: 8,
                      }}>
                        {hero.title}
                      </h3>
                      {hero.description && (
                        <p style={{ fontSize: 14, color: 'var(--text-secondary)', lineHeight: 1.6, marginBottom: 16 }}>
                          {hero.description.slice(0, 120)}{hero.description.length > 120 ? '…' : ''}
                        </p>
                      )}
                      <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                        <div style={{
                          width: 28, height: 28, borderRadius: '50%',
                          background: 'var(--bg-overlay)', overflow: 'hidden',
                          display: 'flex', alignItems: 'center', justifyContent: 'center',
                          fontSize: 11, color: 'var(--accent)', flexShrink: 0,
                        }}>
                          {author?.avatar_url
                            ? <img src={author.avatar_url} style={{ width: '100%', height: '100%', objectFit: 'cover' }} alt="" />
                            : author?.username?.[0]?.toUpperCase()}
                        </div>
                        <span style={{ fontSize: 13, color: 'var(--text-secondary)' }}>
                          {author?.full_name || author?.username}
                        </span>
                        {members.length > 1 && (
                          <span style={{ fontSize: 12, color: 'var(--text-muted)' }}>
                            +{members.length - 1} more
                          </span>
                        )}
                        {hero.semester && (
                          <span style={{ marginLeft: 'auto', fontSize: 12, color: 'var(--text-muted)' }}>
                            {hero.semester}
                          </span>
                        )}
                      </div>
                    </div>
                  </Link>
                )
              })()}

              {/* ── SMALLER CARDS — right column ── */}
              <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
                {restTrending.slice(0, 3).map(p => {
                  const tags   = p.project_tags?.map(pt => pt.tags).filter(Boolean) ?? []
                  const author = p.profiles
                  return (
                    <Link key={p.id} href={`/projects/${p.id}`} style={{
                      display: 'flex', gap: 14,
                      background: 'var(--bg-surface)',
                      border: '1px solid var(--border-subtle)',
                      borderRadius: 14, padding: '16px',
                      textDecoration: 'none',
                      transition: 'all 0.2s cubic-bezier(0.22,1,0.36,1)',
                      flex: 1,
                    }}
                    onMouseEnter={e => {
                      const el = e.currentTarget as HTMLAnchorElement
                      el.style.borderColor = 'var(--accent)'
                      el.style.transform = 'translateX(4px)'
                      el.style.boxShadow = '0 4px 20px rgba(201,151,58,0.1)'
                    }}
                    onMouseLeave={e => {
                      const el = e.currentTarget as HTMLAnchorElement
                      el.style.borderColor = 'var(--border-subtle)'
                      el.style.transform = 'translateX(0)'
                      el.style.boxShadow = 'none'
                    }}>
                      {/* Square thumbnail */}
                      <div style={{
                        width: 72, height: 72, borderRadius: 10, flexShrink: 0,
                        background: 'var(--bg-overlay)', overflow: 'hidden',
                        display: 'flex', alignItems: 'center', justifyContent: 'center',
                        fontSize: 24, color: 'var(--text-muted)',
                      }}>
                        {p.thumbnail_url
                          ? <img src={p.thumbnail_url} style={{ width: '100%', height: '100%', objectFit: 'cover' }} alt="" />
                          : '◫'}
                      </div>
                      <div style={{ flex: 1, minWidth: 0 }}>
                        <div style={{ display: 'flex', gap: 4, flexWrap: 'wrap', marginBottom: 5 }}>
                          {tags.slice(0, 2).map(t => <span key={t!.id} className="tag-pill">{t!.name}</span>)}
                        </div>
                        <h3 style={{
                          fontFamily: 'var(--font-cormorant), Georgia, serif',
                          fontSize: 18, fontWeight: 400, lineHeight: 1.2, marginBottom: 5,
                          overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap',
                        }}>
                          {p.title}
                        </h3>
                        <div style={{ display: 'flex', alignItems: 'center', gap: 8, fontSize: 12, color: 'var(--text-muted)' }}>
                          <div style={{
                            width: 18, height: 18, borderRadius: '50%',
                            background: 'var(--bg-overlay)', overflow: 'hidden', flexShrink: 0,
                            display: 'flex', alignItems: 'center', justifyContent: 'center',
                            fontSize: 9, color: 'var(--accent)',
                          }}>
                            {author?.avatar_url
                              ? <img src={author.avatar_url} style={{ width: '100%', height: '100%', objectFit: 'cover' }} alt="" />
                              : author?.username?.[0]?.toUpperCase()}
                          </div>
                          <span style={{ flex: 1, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                            {author?.username}
                          </span>
                          <span style={{ color: 'var(--accent)', flexShrink: 0 }}>★ {p.star_count}</span>
                          <span style={{ flexShrink: 0 }}>◎ {(p as any).views ?? 0}</span>
                        </div>
                      </div>
                    </Link>
                  )
                })}
              </div>

              {/* ── BOTTOM ROW — remaining ── */}
              {restTrending.slice(3).map(p => {
                const tags = p.project_tags?.map(pt => pt.tags).filter(Boolean) ?? []
                return (
                  <Link key={p.id} href={`/projects/${p.id}`} style={{
                    background: 'var(--bg-surface)',
                    border: '1px solid var(--border-subtle)',
                    borderRadius: 14, overflow: 'hidden',
                    textDecoration: 'none',
                    transition: 'all 0.2s',
                    display: 'flex', flexDirection: 'column',
                  }}
                  onMouseEnter={e => {
                    const el = e.currentTarget as HTMLAnchorElement
                    el.style.borderColor = 'var(--accent)'
                    el.style.transform = 'translateY(-2px)'
                    el.style.boxShadow = '0 8px 24px rgba(201,151,58,0.1)'
                  }}
                  onMouseLeave={e => {
                    const el = e.currentTarget as HTMLAnchorElement
                    el.style.borderColor = 'var(--border-subtle)'
                    el.style.transform = 'translateY(0)'
                    el.style.boxShadow = 'none'
                  }}>
                    <div style={{
                      height: 100, background: 'var(--bg-overlay)', overflow: 'hidden',
                      display: 'flex', alignItems: 'center', justifyContent: 'center',
                      fontSize: 28, color: 'var(--text-muted)',
                    }}>
                      {p.thumbnail_url
                        ? <img src={p.thumbnail_url} style={{ width: '100%', height: '100%', objectFit: 'cover' }} alt="" />
                        : '◫'}
                    </div>
                    <div style={{ padding: '14px' }}>
                      <div style={{ display: 'flex', gap: 4, marginBottom: 5 }}>
                        {tags.slice(0, 2).map(t => <span key={t!.id} className="tag-pill">{t!.name}</span>)}
                      </div>
                      <div style={{ fontFamily: 'var(--font-cormorant), Georgia, serif', fontSize: 17, fontWeight: 400, lineHeight: 1.2, marginBottom: 6 }}>
                        {p.title}
                      </div>
                      <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 11, color: 'var(--text-muted)' }}>
                        <span>@{p.profiles?.username}</span>
                        <span style={{ color: 'var(--accent)' }}>★ {p.star_count}</span>
                      </div>
                    </div>
                  </Link>
                )
              })}
            </div>
          )}
        </section>

        {/* ─── RECENT ASSIGNMENTS ─── */}
        {recentAssignments.length > 0 && (
          <section className="animate-fade-up delay-4">
            <div style={{ display: 'flex', alignItems: 'baseline', justifyContent: 'space-between', marginBottom: 24 }}>
              <h2 style={{ fontFamily: 'var(--font-cormorant), Georgia, serif', fontSize: 40, fontWeight: 400 }}>
                Recent Assignments
              </h2>
              <Link href="/assignments" style={{ fontSize: 13, color: 'var(--accent)', fontWeight: 500 }}>
                View all →
              </Link>
            </div>
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(260px, 1fr))', gap: 14 }}>
              {recentAssignments.map(a => {
                const fs = fileStyle(a.file_url ?? null)
                return (
                  <Link key={a.id} href={`/assignments/${a.id}`} style={{
                    background: 'var(--bg-surface)',
                    border: '1px solid var(--border-subtle)',
                    borderRadius: 14, padding: '18px',
                    display: 'flex', gap: 14, textDecoration: 'none',
                    transition: 'all 0.2s',
                  }}
                  onMouseEnter={e => {
                    const el = e.currentTarget as HTMLAnchorElement
                    el.style.borderColor = 'var(--accent)'
                    el.style.transform = 'translateY(-2px)'
                    el.style.boxShadow = '0 6px 20px rgba(201,151,58,0.08)'
                  }}
                  onMouseLeave={e => {
                    const el = e.currentTarget as HTMLAnchorElement
                    el.style.borderColor = 'var(--border-subtle)'
                    el.style.transform = 'translateY(0)'
                    el.style.boxShadow = 'none'
                  }}>
                    {/* File type icon with color */}
                    <div style={{
                      width: 44, height: 44, borderRadius: 10, flexShrink: 0,
                      background: `${fs.color}18`,
                      border: `1px solid ${fs.color}30`,
                      display: 'flex', alignItems: 'center', justifyContent: 'center',
                      fontSize: 20,
                    }}>
                      {fs.icon}
                    </div>
                    <div style={{ flex: 1, minWidth: 0 }}>
                      <div style={{ fontSize: 10, color: 'var(--accent)', letterSpacing: '0.12em', textTransform: 'uppercase', marginBottom: 4 }}>
                        {a.subject} · {a.semester}
                      </div>
                      <div style={{ fontSize: 14, fontWeight: 500, color: 'var(--text-primary)', marginBottom: 4,
                        overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                        {a.title}
                      </div>
                      <div style={{ fontSize: 11, color: 'var(--text-muted)' }}>
                        by @{a.profiles?.username}
                      </div>
                    </div>
                  </Link>
                )
              })}
            </div>
          </section>
        )}

      </div>
    </div>
  )
}
